args.sqlite_command:
UPDATE J09D_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
    SELECT EQUNR FROM J09D_eabl_flags WHERE is_mandatory = 1
);

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
    SELECT EQUNR FROM J09D_eabl_flags WHERE is_direct_mail = 1
) AND ENTSCHEIDUNG IS NULL;

